import setuptools
import requests
from pkg_resources import Requirement

def fetch_dependencies(config_url):
    response = requests.get(config_url)
    config_data = response.json()
    
    dependencies = []
    for package in config_data['dependencies']:
        try:
            req = Requirement.parse(package)
            dependencies.append(req)
        except Exception as e:
            print(f"Error parsing dependency: {package} - {str(e)}")
    
    return dependencies

def install_dependencies(dependencies):
    try:
        setuptools.setup(install_requires=[req.key for req in dependencies])
        
        # Install additional packages needed at install time
        for package in config_data['additional_packages']:
            print(f"Installing additional package: {package}")
            import subprocess
            subprocess.run(['pip', 'install', package], check=True)
    except Exception as e:
        print(f"Error installing dependencies: {str(e)}")

config_url = 'https://example.com/config.json'
dependencies = fetch_dependencies(config_url)
install_dependencies(dependencies)